import React, { useState, useEffect } from "react";
import {
    CButton,
    CCard,
    CCardBody,
    CCol,
    CContainer,
    CForm,
    CFormInput,
    CInputGroup,
    CInputGroupText,
    CRow,
    CModal,
    CModalHeader,
    CModalTitle,
    CModalBody,
    CModalFooter,
    CFormLabel
} from "@coreui/react";
import CIcon from "@coreui/icons-react";
import { cilLockLocked, cilUser,cilEnvelopeClosed} from "@coreui/icons";
// Assuming authService and updatePosition are imported correctly
import authService from "src/auth/auth.service";
import { updateState } from "src/utils/utils";
import { useParams,useNavigate } from "react-router-dom";
import { getEnableRoles, getUserDataById, updateUser, updateUserPassword } from "src/components/services/UserApi";
import alertPopUp from 'sweetalert2';
import withReactContent from 'sweetalert2-react-content';
import { errorMessagePopUp } from "src/utils/Common";
import Select from 'react-select';
import GoBackComponent from "src/utils/GoBackComponent";


const MySwal = withReactContent(alertPopUp);

function UpdateUser() {
    const [state, setState] = useState({ email: '', password: '', newPassword: "", username: '', selectedCheckboxes: [] , editRoleList: []});
    const [loading, setLoading] = useState(false);
    const [errors, setErrors] = useState({
        username: "",
        email: "",
        password: "",
        newPassword: "",
        permission: "",
        role: ""
    });
    const [message, setMessage] = useState("")
    const [visible, setVisible] = useState(false);
    const [visiblePassword, setVisiblePassword] = useState(false);
    const [visibility, setVisibility] = useState(false)
    const checkBoxData = [
        "BUSINESS", "CONTACT", "TESTIMONIAL", "RESOURCE", "TEAM", "CAREER", "USER"
    ];
    const { id } = useParams();
    const navigate = useNavigate();
    const [rolesList,setRolesList] = useState([]);
    const [selectedRole,setSelectedRole] = useState([])



    const handleInputChange = (e) => {
        const { name, value } = e.target;
        const newState = updateState(state, { [name]: value.replace(/ /g,"")});
        setState(newState);
    };

    const handleCheckboxChange = (e) => {
        const { name, checked } = e.target;
        const updatedCheckboxes = checked
            ? [...state.selectedCheckboxes, name]
            : state.selectedCheckboxes.filter(item => item !== name);
        setState(prevState => ({ ...prevState, selectedCheckboxes: updatedCheckboxes }));
    };

    const validateForm = () => {
        const validationErrors = {};

        // Username validation
        if (!state.username) {
            validationErrors.username = "Username is required";
        }
        if (/[\d!@#$%^&*()_+=[\]{};':"\\|,.<>/?]+/.test(state.username)) {
            validationErrors.username = "Username should not contain numerical or special characters";
        }

        // Email validation
        if (!state.email) {
            validationErrors.email = "Email is required";
        }

        // Password validation
        // if (!state.password) {
        //     validationErrors.password = "Password is required";
        // }  
        // if (state.password?.length < 8) {
        //     validationErrors.password = "Password must be at least 8 characters long";
        // } 
        // if (!/[A-Z]/.test(state.password)) {
        //     validationErrors.password = "Password must contain at least 1 uppercase character";
        // }

        // Permission validation
        // if (state.selectedCheckboxes.length === 0) {
        //     validationErrors.permission = "Select at least one permission";
        // }

          // role validation
        if (selectedRole.length === 0) {
            validationErrors.role = "Select at least one role";
        }

        // Confirm password validation
        // if (!state.newPassword || state.password !== state.newPassword) {
        //     validationErrors.newPassword = "Passwords do not match";
        // }

        setErrors(validationErrors);

        return Object.keys(validationErrors).length === 0;
    };

    const validatePasswordForm = () => {
        const validationErrors = {};


        // Password validation
        if (!state.password) {
            validationErrors.password = "Password is required";
        }  
        if (state.password?.length < 8) {
            validationErrors.password = "Password must be at least 8 characters long";
        } 
        if (!/[A-Z]/.test(state.password)) {
            validationErrors.password = "Password must contain at least 1 uppercase character";
        }

        // Confirm password validation
        if (!state.newPassword || state.password !== state.newPassword) {
            validationErrors.newPassword = "Passwords do not match";
        }

        setErrors(validationErrors);

        return Object.keys(validationErrors).length === 0;
    };

    const handleLogin = async (event) => {
        event.preventDefault();
        const isFormValid = validateForm();

        if (!isFormValid) {
            setTimeout(() => {
                setErrors({
                    username: false,
                    email: false,
                    // password: false,
                    // newPassword: false,
                });
            }, 2000);
            return;
        }
        let role = selectedRole && selectedRole.map(data => {return data?.value})
        setLoading(true);

        try {
            let postData = {
                name: state.username,
                email: state.email,
                id: id,
                // permission: state.selectedCheckboxes,
                role: role
            };

            const user = await updateUser(postData); // Make sure `updateUser` function is correctly implemented

            if (user?.message === "Email already exists") {
                errorMessagePopUp(user?.message);
            }
            if (user?.code === 202) {
                navigate("/user");
            }
            setLoading(false);
            setErrors({
                username: false,
                email: false,
                password: false,
                newPassword: false,
            });
        } catch (error) {
            console.error("Failed to update user:", error.message);

            setLoading(false);
        }
    };


    const  handleResetPassword = async (event) => {
        event.preventDefault();
        const isPasswordFormValid = validatePasswordForm();

        if (!isPasswordFormValid) {
            setTimeout(() => {
                setErrors({
                    password: false,
                    newPassword: false,
                });
            }, 2000);
            return;
        }

        setLoading(true);

        try {
            let postData = {
                email: state.email,
                password: state.password,
                id: id
            };

            const response = await updateUserPassword(postData);

            if (response?.code === 202) {
                setVisible(false)
                navigate("/user");
            }
            setLoading(false);
            setErrors({
                email: false,
                password: false,
                newPassword: false,
            });
        } catch (error) {
            console.error("Failed to update user:", error.message);

            setLoading(false);
        }
    };

    // Function to fetch user data by id and populate the input fields
    useEffect(() => {
        fetchEnableRoles();
        const fetchUserData = async () => {
            try {
                const response = await getUserDataById(id); // Assuming getUserDataById returns an object with user details
                // Populate the input fields with the fetched user data
                if(response?.code === 200){
                    let user = response?.results;
                    setState({
                        email: user.email || '',
                        password: user?.password,
                        newPassword: user?.password,
                        username: user.name || '',
                        // selectedCheckboxes: user.permission[0] === "ADMIN" ? checkBoxData : (user.permission  || [])
                        editRoleList : user.role

                    });
                }
            } catch (error) {
                console.error("Failed to fetch user data:", error.message);
            }
        };

        fetchUserData(); // Call the function to fetch user data on component mount
    }, [id]);

    const handleVisibility = (type) => {
        if(type === "PASSWORD"){
            setVisiblePassword(!visiblePassword)
        }else{
            setVisibility(!visibility)
        }
    }
    const handleReset = () => {
        let  formData = state;
        formData.password = '';
        formData.newPassword = '';
        setState(formData);
        setVisible(false);
      };


    useEffect(() => {

        if (rolesList && rolesList.length > 0 && state.editRoleList) {
            let editRoleDetails = state.editRoleList.map(id => {
              let roleDetails = rolesList.find(data => data?.value === id);
              return { value: roleDetails?.value, label: roleDetails?.label.toUpperCase() };
            });
            setSelectedRole(editRoleDetails);
          }
    }, [message, state, rolesList])


    const fetchEnableRoles = async () => {
        let response = await getEnableRoles();
        let roleData = [];
        if(response?.code === 200){
            response.results &&  response.results.map(item => {roleData.push({value: item?._id, label: item?.name})})
            setRolesList(roleData)
        }
    };

    const handleChangeRole = (role) => {
        setSelectedRole(role);
    };

    return (
        <div>
            <GoBackComponent goBackData={"user"} />
            <CContainer>
                <CRow className="justify-content-center">
                    <CCol md={12} lg={12} xl={12}>
                        <CCard className="mx-4">
                            <CCardBody className="p-4">
                                <CForm>
                                    <h1>Update User</h1>
                                    <p className="text-medium-emphasis">Update user account</p>
                                    <CInputGroup className="mb-3">
                                        <CInputGroupText>
                                            <CIcon icon={cilUser} />
                                        </CInputGroupText>
                                        <CFormInput
                                            placeholder="Username"
                                            autoComplete="username"
                                            onChange={handleInputChange}
                                            name="username"
                                            value={state.username}
                                            invalid={errors.username}
                                        />
                                        {errors.username && <p className="invalid-feedback">{errors.username}</p>}
                                    </CInputGroup>
                                    <CInputGroup className="mb-3">
                                        <CInputGroupText><CIcon icon={cilEnvelopeClosed} /></CInputGroupText>
                                        <CFormInput
                                            placeholder="Email"
                                            autoComplete="email"
                                            onChange={handleInputChange}
                                            name="email"
                                            value={state.email}
                                            invalid={errors.email}
                                            disabled={true}
                                        />
                                        {errors.email && <p className="invalid-feedback">{errors.email}</p>}
                                    </CInputGroup>

                                    {/* <p className="text-medium-emphasis">Permission</p> */}
                                    {/* {checkBoxData.map((item) => (
                                        <CInputGroup className="mb-2" key={item}>
                                            <CInputGroupText>
                                                <input
                                                    type="checkbox"
                                                    name={item}
                                                    checked={state.selectedCheckboxes.includes(item)}
                                                    onChange={handleCheckboxChange}
                                                />
                                            </CInputGroupText>
                                            <span style={{ paddingLeft: "15px" }}>{item}</span>
                                        </CInputGroup>
                                    ))} */}

                                    <CFormLabel htmlFor='exampleFormControlTextarea1'>Select Role <span className='text-danger'>*</span></CFormLabel>
                                    <Select
                                        isMulti
                                        value={selectedRole}
                                        options={rolesList && rolesList.map(item => ({value: item.value, label: item.label.toUpperCase()}))}
                                        onChange={handleChangeRole}
                                        placeholder={"Start typing"}
                                        closeMenuOnSelect={false}
                                        classNamePrefix="select"
                                        styles={{
                                            control: styles => ({ ...styles, borderColor: errors["role"] && 'red', height: '50px' }),
                                            option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                                                const color = '#03a68059';
                                                return {
                                                    ...styles,
                                                    backgroundColor: isDisabled
                                                        ? null
                                                        : isSelected
                                                            ? '#03a68059'
                                                            : isFocused
                                                                ? '#03a68059'
                                                                : null,
                                                    color: isDisabled
                                                        ? '#ccc'
                                                        : isSelected
                                                            ? color > 2
                                                                ? '#00374d'
                                                                : '#00374d'
                                                            : data.color,
                                                    cursor: isDisabled ? 'not-allowed' : 'default',

                                                    ':active': {
                                                        ...styles[':active'],
                                                        backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                                                    },
                                                };
                                            },
                                        }}
                                    />
                                    {errors.role && <p style={{color: "#e55353",fontSize: "0.875em"}} >{errors.role}</p>}

                                    {/* {errors.permission && <p className="invalid-feedback">{errors.permission}</p>} */}
                                     <div style={{ display: 'flex', gap: '10px',justifyContent:"center",marginTop:'15px' }}>
                                        <CButton color="success" onClick={handleLogin} disabled={loading}>
                                            {loading ? "Updating..." : "Update"}
                                        </CButton>

                                        <CButton  color="secondary" onClick={() => setVisible(!visible)}>
                                            {"Reset Password"}
                                        </CButton>
                                    </div>
                                </CForm>
                            </CCardBody>
                        </CCard>

                        <CModal  visible={visible} onClose={() => {handleReset()}}>
                            <CModalHeader>
                                <CModalTitle>RESET YOUR PASSWORD</CModalTitle>
                            </CModalHeader>

                            <CModalBody>
                                        <CInputGroup className="mb-3">
                                            <CInputGroupText> <CIcon icon={cilLockLocked} /></CInputGroupText>
                                            <CFormInput
                                                 type= {visiblePassword ? "text" : "password"}
                                                placeholder="Password"
                                                autoComplete="new-password"
                                                onChange={handleInputChange}
                                                name="password"
                                                value={state.password}
                                                invalid={errors.password}
                                        />
                                            <CInputGroupText style={{cursor : "pointer"}} onClick={() => {handleVisibility('PASSWORD')}}>{!visibility ? "Show" : "Hide"}</CInputGroupText>
                                            {errors.password && <p className="invalid-feedback">{errors.password}</p>}
                                    </CInputGroup>



                                    <CInputGroup className="mb-3">
                                            <CInputGroupText> <CIcon icon={cilLockLocked} /></CInputGroupText>
                                            <CFormInput
                                                type= {visibility ? "text" : "password"}
                                                placeholder="Confirm password"
                                                autoComplete="new-password"
                                                onChange={handleInputChange}
                                                name="newPassword"
                                                value={state.newPassword}
                                                invalid={errors.newPassword}
                                            />
                                            <CInputGroupText style={{cursor : "pointer"}} onClick={() => {handleVisibility('CONFIRM_PASSWORD')}}>{!visibility ? "Show" : "Hide"}</CInputGroupText>
                                    </CInputGroup>
                            </CModalBody>

                            <CModalFooter>
                                <CButton color="secondary" onClick={() => {handleReset()}}>
                                Close
                                </CButton>
                                <CButton color="success" onClick={handleResetPassword} disabled={loading}>
                                            {loading ? "Update Password..." : "Update Password"}
                                </CButton>
                            </CModalFooter>
                        </CModal>

                    </CCol>
                </CRow>
            </CContainer>
        </div>
    );
}

export default UpdateUser;
